ref_rebind_illusion.template:
#include <iostream>
#include <cstdio>
int main() {
    int a = 10;
    int b = 20;
    int& r = a;
    r = b;  // assigns b's value to a, does NOT rebind r
    printf("&r == &a: %s\n", (&r == &a ? "true" : "false"));
    printf("a=%d, b=%d, r=%d\n", a, b, r);
    printf("PTRDATA: type=ref ref_addr=%p target_addr=%p target_val=%d\n",
           (void*)&r, (void*)&a, a);
    <<HARNESS>>
}

